(function(){"use strict";let r=null,f=null,L=null;self.onmessage=function(j){const{type:k,data:m}=j.data;if(k==="init"){r=m.posHome,f=m.randomDir,L=m.randomSpeed;return}if(k==="update"){const{posLive:c,springDisp:e,springVel:s,count:w,dt:P,time:A,elapsed:x,isMotionReduced:B,mouseLocal:M,kFrame:D,dampFrame:z,expansionDuration:g,contractionDuration:C,explosionMaxDistMultiplier:E,mouseInfluence:y,repulsionStr:G}=m;if(!r){self.postMessage({type:"update",posLive:c,springDisp:e,springVel:s});return}const J=y*y;for(let d=0;d<w;d++){const t=d*3,n=t+1,o=t+2;let h=r[t],b=r[n],S=r[o];if(!B){const i=A*1.3+d*.005;h+=Math.sin(i)*.12,b+=Math.cos(i*.8)*.08,S+=Math.sin(i*.5)*.15}if(x>0){const i=L[d]*E,l=f[t],I=f[n],u=f[o];let p;if(x<g){const a=x/g;p=i*a*(2-a)}else{const a=(x-g)/C;p=i*(1-a*a*a)}h+=l*p,b+=I*p,S+=u*p}const K=c[t],N=c[n],O=c[o],_=K-M.x,v=N-M.y,F=O-M.z,H=_*_+v*v+F*F;let q=0,R=0,V=0;if(H<J&&H>1e-5){const i=Math.sqrt(H),l=1/i,I=(y-i)/y,u=G*I;q=_*l*u,R=v*l*u,V=F*l*u}s[t]=(s[t]+(q-e[t])*D)*z,s[n]=(s[n]+(R-e[n])*D)*z,s[o]=(s[o]+(V-e[o])*D)*z,e[t]+=s[t],e[n]+=s[n],e[o]+=s[o],c[t]=h+e[t],c[n]=b+e[n],c[o]=S+e[o]}self.postMessage({type:"update",posLive:c,springDisp:e,springVel:s})}}})();
